module RefModule (
	input clk,
	input reset,
	input load,
	input [7:0] data,
	output reg [7:0] count);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		count <= 8'b0;
	else if (load)
		count <= data;
	else
		count <= count + 1'b1;
end

endmodule
